+
+  private getKeysetPagination(opts: CrudOptions): {
+    sort: { field: string; direction: 'asc' | 'desc' }[];
+    where?: Record<string, any>;
+  } | null {
+    if (opts.cursor && !opts.orderBy) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (opts.cursor && opts.offset !== undefined) {
+      throw new BadRequestException('cursor cannot be used with offset');
+    }
+    if (!opts.orderBy || !opts.limit) {
+      return null;
+    }
+
+    const sort = this.getCursorSort(opts.orderBy);
+    opts.orderBy = Object.fromEntries(
+      sort.map(({ field, direction }) => [field, direction]),
+    ) as any;
+
+    if (!opts.cursor) {
+      return { sort };
+    }
+
+    const payload = this.decodeCursor(opts.cursor);
+    const expectedSort = sort
+      .map(({ field, direction }) => `${field}:${direction}`)
+      .join(',');
+    if (payload.__sort !== expectedSort) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    for (const { field } of sort) {
+      if (!Object.prototype.hasOwnProperty.call(payload, field)) {
+        throw new BadRequestException(`cursor is missing ${field}`);
+      }
+    }
+    if (!Object.prototype.hasOwnProperty.call(payload, this.crudConfig.id_field)) {
+      throw new BadRequestException('cursor is missing entity ID');
+    }
+
+    return { sort, where: this.getKeysetWhere(payload, sort) };
+  }
+
+  private getCursorSort(orderBy: any): {
+    field: string;
+    direction: 'asc' | 'desc';
+  }[] {
+    const entries = (Array.isArray(orderBy) ? orderBy : [orderBy]).flatMap(
+      (part) => Object.entries(part || {}),
+    );
+    const sort = entries.map(([field, value]) => ({
+      field,
+      direction: this.getCursorDirection(value),
+    }));
+    if (!sort.length) {
+      throw new BadRequestException('cursor requires a non-empty orderBy');
+    }
+    if (!sort.some(({ field }) => field === this.crudConfig.id_field)) {
+      sort.push({ field: this.crudConfig.id_field, direction: 'asc' });
+    }
+    return sort;
+  }
+
+  private getCursorDirection(value: any): 'asc' | 'desc' {
+    if (value === 1 || String(value).toLowerCase().startsWith('asc')) {
+      return 'asc';
+    }
+    if (value === -1 || String(value).toLowerCase().startsWith('desc')) {
+      return 'desc';
+    }
+    throw new BadRequestException('orderBy direction must be asc or desc');
+  }
+
+  private decodeCursor(cursor: string): Record<string, any> {
+    try {
+      const payload = JSON.parse(Buffer.from(cursor, 'base64').toString('utf8'));
+      if (!payload || Array.isArray(payload) || typeof payload !== 'object') {
+        throw new Error('cursor payload is not an object');
+      }
+      return payload;
+    } catch {
+      throw new BadRequestException('cursor must be Base64-encoded JSON');
+    }
+  }
+
+  private getKeysetWhere(
+    payload: Record<string, any>,
+    sort: { field: string; direction: 'asc' | 'desc' }[],
+  ) {
+    return {
+      $or: sort.map(({ field, direction }, index) => ({
+        $and: [
+          ...sort
+            .slice(0, index)
+            .map(({ field }) => ({ [field]: payload[field] })),
+          { [field]: { [direction === 'asc' ? '$gt' : '$lt']: payload[field] } },
+        ],
+      })),
+    };
+  }
+
+  private createCursor(
+    entity: T,
+    sort: { field: string; direction: 'asc' | 'desc' }[],
+  ) {
+    const payload: Record<string, any> = {};
+    for (const { field } of sort) {
+      payload[field] = entity[field];
+    }
+    payload[this.crudConfig.id_field] = entity[this.crudConfig.id_field];
+    payload.__sort = sort
+      .map(({ field, direction }) => `${field}:${direction}`)
+      .join(',');
+    return Buffer.from(JSON.stringify(payload)).toString('base64');
+  }
