  async $find(
    entity: Partial<T>,
    ctx: CrudContext<T>,
    opOptions: OpParams<T> = { secure: true },
    inheritance?: Inheritance,
  ): Promise<FindResponseDto<T>> {
    const opParams = this.getOpParams(opOptions, ctx);
    try {
      if (!opParams.options?.skipServiceHooks) {
        entity = await this.beforeReadHook(entity, ctx);
      }

      if (Array.isArray(entity[this.crudConfig.id_field])) {
        this.makeInQuery(entity[this.crudConfig.id_field], entity);
      }

      this.checkObjectForIds(entity);

      const em = opParams.em || this.entityManager.fork();
      const opts = this.getReadOptions(ctx, opParams);
      const keyset = this.getKeysetPagination(opts);
      let findEntity: Partial<T> = entity;
      if (keyset?.where) {
        findEntity = { $and: [entity, keyset.where] } as unknown as Partial<T>;
      }
      let result: FindResponseDto<T>;
      if (opts.limit) {
        const findOpts = keyset ? { ...opts, limit: opts.limit + 1 } : opts;
        const res = await em.findAndCount(
          this.entity,
          findEntity,
          findOpts as any,
        );
        const data = keyset ? res[0].slice(0, opts.limit) : res[0];
        result = {
          data,
          total: keyset.where ? await em.count(this.entity, entity) : res[1],
          limit: opts.limit,
        };
        if (keyset && res[0].length > opts.limit) {
          result.nextCursor = this.createCursor(
            data[data.length - 1],
            keyset.sort,
          );
        }
      } else {
        const res = await em.find(this.entity, findEntity, opts as any);
        result = { data: res };
      }
      if (!opParams.options?.skipServiceHooks) {
        result = await this.afterReadHook(result, entity, ctx);
      }
      return result;
    } catch (e) {
      if (!opParams.options?.skipServiceHooks) {
        const res = await this.errorReadHook(entity, ctx, e);
        if (res) {
          return res;
        }
      }
      throw e;
    }
  }

  async $findIds(
    entity: Partial<T>,
    ctx: CrudContext<T>,
    opOptions: OpParams<T> = { secure: true },
    inheritance?: Inheritance,
  ): Promise<string[]> {
    const newOpts: OpParams<T> = {
      ...opOptions,
      options: {
        ...(opOptions.options || {}),
        fields: [this.crudConfig.id_field as any],
      },
    };
    const res = await this.$find(entity, ctx, newOpts);
    return res.data.map((d) => d[this.crudConfig.id_field]);
  }

  async $findIn_(ctx: CrudContext<T>) {
    return this.$findIn(ctx.ids, ctx.query, ctx, {
      options: ctx.queryOptions,
    });
  }

  async $findIn(
    ids: string[],
    entity: Partial<T>,
    ctx: CrudContext<T>,
    opOptions: OpParams<T> = { secure: true },
    inheritance?: Inheritance,
  ) {
    this.makeInQuery(ids, entity);
    return this.$find(entity, ctx, opOptions, inheritance);
  }

  getReadOptions(ctx: CrudContext<T>, opOptions: OpParams): CrudOptions {
    const opts = { ...(opOptions?.options || {}) };
    return opts;
  }

  private getKeysetPagination(opts: CrudOptions): {
    sort: { field: string; direction: 'asc' | 'desc' }[];
    where?: Record<string, any>;
  } | null {
    if (opts.cursor && !opts.orderBy) {
      throw new BadRequestException('cursor requires orderBy');
    }
    if (opts.cursor && opts.offset !== undefined) {
      throw new BadRequestException('cursor cannot be used with offset');
    }
    if (!opts.orderBy || !opts.limit) {
      return null;
    }

    const sort = this.getCursorSort(opts.orderBy);
    opts.orderBy = this.appendIdToOrderBy(opts.orderBy) as any;

    if (!opts.cursor) {
      return { sort };
    }

    const payload = this.decodeCursor(opts.cursor);
    const expectedSort = sort
      .map(({ field, direction }) => `${field}:${direction}`)
      .join(',');
    if (payload.__sort !== expectedSort) {
      throw new BadRequestException('cursor sort does not match orderBy');
    }
    for (const { field } of sort) {
      if (!Object.prototype.hasOwnProperty.call(payload, field)) {
        throw new BadRequestException(`cursor is missing ${field}`);
      }
    }
    if (
      !Object.prototype.hasOwnProperty.call(payload, this.crudConfig.id_field)
    ) {
      throw new BadRequestException('cursor is missing entity ID');
    }

    return { sort, where: this.getKeysetWhere(payload, sort) };
  }

  private getCursorSort(orderBy: any): {
    field: string;
    direction: 'asc' | 'desc';
  }[] {
    const entries = (Array.isArray(orderBy) ? orderBy : [orderBy]).flatMap(
      (part) => Object.entries(part || {}),
    );
    const sort = entries.map(([field, value]) => ({
      field,
      direction: this.getCursorDirection(value),
    }));
    if (!sort.length) {
      throw new BadRequestException('cursor requires a non-empty orderBy');
    }
    if (!sort.some(({ field }) => field === this.crudConfig.id_field)) {
      sort.push({ field: this.crudConfig.id_field, direction: 'asc' });
    }
    return sort;
  }

  private getCursorDirection(value: any): 'asc' | 'desc' {
    if (value === 1 || String(value).toLowerCase().startsWith('asc')) {
      return 'asc';
    }
    if (value === -1 || String(value).toLowerCase().startsWith('desc')) {
      return 'desc';
    }
    throw new BadRequestException('orderBy direction must be asc or desc');
  }

  private appendIdToOrderBy(orderBy: any) {
    const hasId = (Array.isArray(orderBy) ? orderBy : [orderBy]).some((part) =>
